-- ============================================================================
-- ARCTOS Seed: ISO/IEC 27018:2019 — PII Protection in Public Cloud
-- Source: ISO/IEC 27018:2019 (Code of practice for PII protection in
--         public clouds acting as PII processors)
--
-- Structure: ISO 27018 extends ISO 27002 with privacy-specific guidance and
-- adds an Annex A with 25 PII-processor obligations. This seed includes
-- the 11 main thematic areas and the 25 Annex A obligations.
--
-- Target modules: dpms, isms, tprm
-- ============================================================================

INSERT INTO catalog (id, name, description, catalog_type, scope, source, version, language, is_active, target_modules)
VALUES (
  'c0000000-0000-0000-0000-270180000001',
  'ISO/IEC 27018:2019 PII Cloud Protection',
  'Code of practice for protection of Personally Identifiable Information (PII) in public clouds acting as PII processors. Extends ISO 27002 with 25 cloud-PII-processor obligations.',
  'control', 'platform', 'iso_27018_2019', '2019', 'en', true, '{dpms,isms,tprm}'
) ON CONFLICT (id) DO NOTHING;

INSERT INTO catalog_entry (catalog_id, code, name, name_de, description, description_de, level, sort_order, status) VALUES
-- ── Annex A: PII-Processor Obligations (25 controls) ─────────────────────
('c0000000-0000-0000-0000-270180000001', 'A.1', 'Consent and Choice', 'Einwilligung und Wahlmöglichkeit', 'PII-processor obligations regarding the customer''s right to control PII', 'Verpflichtungen des PII-Verarbeiters zum Kontrollrecht des Kunden über PII', 0, 100, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.1.1', 'Obligation to co-operate regarding PII principals'' rights', 'Mitwirkungspflicht bei Rechten der Betroffenen', 'The cloud-service provider shall provide the cloud-service customer with means to comply with rights of PII principals.', 'Der Cloud-Dienstleister muss dem Kunden Mittel bereitstellen, um die Rechte der Betroffenen zu erfüllen.', 1, 110, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.2', 'Purpose Legitimacy and Specification', 'Zweckbindung und Zweckangabe', 'PII shall only be processed for purposes specified by the customer', 'PII darf nur für die vom Kunden spezifizierten Zwecke verarbeitet werden', 0, 200, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.2.1', 'Public cloud PII processor''s purpose', 'Zweck des öffentlichen Cloud-PII-Verarbeiters', 'PII to be processed under a contract shall not be processed for any purpose independent of the instructions of the cloud-service customer.', 'PII darf nur entsprechend den Weisungen des Cloud-Kunden verarbeitet werden.', 1, 210, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.2.2', 'Public cloud PII processor''s commercial use', 'Kommerzielle Nutzung verboten', 'PII processed under a contract shall not be used by the cloud-service provider for the purposes of marketing and advertising without express consent.', 'PII darf vom Provider nicht für Marketing und Werbung ohne ausdrückliche Einwilligung genutzt werden.', 1, 220, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.3', 'Collection Limitation', 'Erhebungsbegrenzung', 'PII collection shall be limited to what is necessary', 'PII-Erhebung muss auf das Notwendige begrenzt sein', 0, 300, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.4', 'Data Minimization', 'Datenminimierung', 'PII shall be minimised through technical and organisational means', 'PII muss durch technische und organisatorische Maßnahmen minimiert werden', 0, 400, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.4.1', 'Secure erasure of temporary files', 'Sichere Löschung temporärer Dateien', 'Temporary files containing PII shall be erased or destroyed within a defined time-frame.', 'Temporäre Dateien mit PII müssen innerhalb eines definierten Zeitraums gelöscht oder zerstört werden.', 1, 410, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.5', 'Use, Retention and Disclosure Limitation', 'Verwendungs-, Aufbewahrungs- und Offenlegungsbegrenzung', 'PII shall not be used, retained or disclosed beyond contracted purposes', 'PII darf nicht über die vertraglichen Zwecke hinaus verwendet, aufbewahrt oder offengelegt werden', 0, 500, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.5.1', 'PII disclosure notification', 'Benachrichtigung bei PII-Offenlegung', 'Provider shall notify customer of any legally binding request for disclosure of PII by a law-enforcement authority unless prohibited by law.', 'Der Provider muss den Kunden über jede rechtsverbindliche PII-Offenlegungsanforderung von Strafverfolgungsbehörden informieren, sofern dies nicht gesetzlich verboten ist.', 1, 510, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.5.2', 'Recording of PII disclosures', 'Dokumentation von PII-Offenlegungen', 'Disclosures of PII to third parties shall be recorded, including what PII has been disclosed, to whom and at what time.', 'Offenlegungen von PII an Dritte müssen dokumentiert werden, inkl. welche PII, an wen und wann.', 1, 520, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.6', 'Accuracy and Quality', 'Richtigkeit und Qualität', 'PII shall be accurate and up to date', 'PII muss korrekt und aktuell sein', 0, 600, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.7', 'Openness, Transparency and Notice', 'Offenheit, Transparenz und Benachrichtigung', 'PII processing shall be open and transparent', 'PII-Verarbeitung muss offen und transparent erfolgen', 0, 700, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.7.1', 'Disclosure of sub-contracted PII processing', 'Offenlegung von Unterauftragsverarbeitern', 'Use of sub-contractors to process PII shall be disclosed to the cloud-service customer before use.', 'Der Einsatz von Unterauftragsverarbeitern muss dem Kunden vor Nutzung offengelegt werden.', 1, 710, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.8', 'Individual Participation and Access', 'Recht der Betroffenen auf Zugang', 'PII principals shall have access to their PII', 'Betroffene müssen Zugang zu ihren PII haben', 0, 800, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.9', 'Accountability', 'Rechenschaftspflicht', 'Accountability for PII processing shall be established', 'Rechenschaftspflicht für PII-Verarbeitung muss etabliert werden', 0, 900, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.9.1', 'Notification of PII breach', 'Meldung von PII-Verletzungen', 'Provider shall notify customer of any breach involving PII processed under the contract within a defined timeframe.', 'Der Provider muss den Kunden innerhalb eines definierten Zeitrahmens über jede PII-Verletzung im Rahmen des Vertrags informieren.', 1, 910, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.9.2', 'Retention period for administrative security policies', 'Aufbewahrung administrativer Sicherheitsrichtlinien', 'Administrative security policies relating to PII processing shall be reviewed and retained for a defined period.', 'Administrative Sicherheitsrichtlinien zur PII-Verarbeitung müssen geprüft und für einen definierten Zeitraum aufbewahrt werden.', 1, 920, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.9.3', 'PII return, transfer and disposal', 'Rückgabe, Transfer und Entsorgung von PII', 'On termination of the contract, the provider shall return, transfer or securely dispose of PII as instructed.', 'Bei Vertragsende muss der Provider PII gemäß Weisung zurückgeben, übertragen oder sicher entsorgen.', 1, 930, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10', 'Information Security', 'Informationssicherheit', 'PII shall be protected by appropriate security controls', 'PII muss durch angemessene Sicherheitsmaßnahmen geschützt werden', 0, 1000, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.1', 'Confidentiality / non-disclosure agreements', 'Vertraulichkeits-/Geheimhaltungsvereinbarungen', 'Personnel of the provider with access to PII shall sign confidentiality / NDA agreements.', 'Personal des Providers mit PII-Zugang muss Vertraulichkeits-/NDA-Vereinbarungen unterzeichnen.', 1, 1010, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.2', 'Restriction of creation of hardcopy material', 'Beschränkung der Erstellung von Hardcopy-Material', 'Creation of hardcopy material containing PII shall be restricted to what is required.', 'Die Erstellung von Hardcopy-Material mit PII muss auf das Notwendige beschränkt werden.', 1, 1020, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.3', 'Control and logging of data restoration', 'Kontrolle und Protokollierung der Datenwiederherstellung', 'There shall be a procedure for, and a log of, data restoration efforts.', 'Es muss ein Verfahren und Protokoll für Datenwiederherstellungs-Aktivitäten geben.', 1, 1030, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.4', 'Protecting data on storage media leaving the premises', 'Schutz von Daten auf Speichermedien, die das Gelände verlassen', 'PII on portable physical media or transmitted over networks shall be encrypted.', 'PII auf tragbaren Speichermedien oder bei Netzwerkübertragung muss verschlüsselt werden.', 1, 1040, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.5', 'Use of unencrypted portable storage media and devices', 'Nutzung unverschlüsselter tragbarer Speichermedien', 'Unencrypted portable storage media shall not be used to transfer PII unless explicitly approved.', 'Unverschlüsselte tragbare Speichermedien dürfen nicht zur PII-Übertragung verwendet werden, außer mit ausdrücklicher Genehmigung.', 1, 1050, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.6', 'Encryption of PII in transit', 'Verschlüsselung von PII bei Übertragung', 'PII transmitted over public networks shall be encrypted using industry-standard algorithms.', 'PII, die über öffentliche Netzwerke übertragen wird, muss mit Industrie-Standard-Algorithmen verschlüsselt werden.', 1, 1060, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.7', 'Secure disposal of hardcopy materials', 'Sichere Entsorgung von Hardcopy-Material', 'Hardcopy materials containing PII shall be securely destroyed when no longer needed.', 'Hardcopy-Material mit PII muss sicher zerstört werden, sobald nicht mehr benötigt.', 1, 1070, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.8', 'Unique use of user IDs', 'Eindeutige Verwendung von User-IDs', 'User IDs shall be uniquely allocated to individuals; shared user IDs shall be avoided.', 'User-IDs müssen eindeutig Personen zugeordnet werden; geteilte User-IDs sind zu vermeiden.', 1, 1080, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.9', 'Records of authorized users', 'Aufzeichnungen autorisierter Benutzer', 'A record of users with authorized access to PII shall be maintained.', 'Eine Aufzeichnung der Benutzer mit autorisiertem PII-Zugang muss geführt werden.', 1, 1090, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.10', 'User ID management', 'User-ID-Management', 'User IDs that are no longer needed shall be deactivated or removed in a timely manner.', 'Nicht mehr benötigte User-IDs müssen zeitnah deaktiviert oder entfernt werden.', 1, 1100, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.11', 'Contract measures', 'Vertragsmaßnahmen', 'Contracts between the cloud-service provider and customer shall specify minimum technical and organisational measures.', 'Verträge zwischen Cloud-Provider und Kunde müssen technische und organisatorische Mindestmaßnahmen spezifizieren.', 1, 1110, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.12', 'Sub-contracted PII processing', 'PII-Verarbeitung durch Unterauftragsverarbeiter', 'Sub-contracts for PII processing shall impose the same obligations as the prime contract.', 'Unterauftragsverträge für PII-Verarbeitung müssen die gleichen Verpflichtungen wie der Hauptvertrag auferlegen.', 1, 1120, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.10.13', 'Access to data on pre-used data storage space', 'Zugang zu Daten auf wiederverwendetem Speicher', 'When data storage space is reallocated, residual PII from prior tenants shall not be accessible.', 'Bei Speicher-Wiederverwendung darf keine Rest-PII vorheriger Mandanten zugänglich sein.', 1, 1130, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.11', 'Privacy Compliance', 'Privacy-Compliance', 'Compliance with applicable privacy laws and regulations', 'Compliance mit anwendbaren Datenschutzgesetzen und -vorschriften', 0, 1200, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.11.1', 'Geographical location of PII', 'Geografischer Standort von PII', 'The cloud-service provider shall specify and document the countries in which PII may be stored.', 'Der Cloud-Provider muss die Länder, in denen PII gespeichert werden kann, spezifizieren und dokumentieren.', 1, 1210, 'active'),
('c0000000-0000-0000-0000-270180000001', 'A.11.2', 'Intended destination of PII', 'Beabsichtigtes Ziel von PII', 'PII transmitted to a third country shall be processed in compliance with applicable data-transfer regulations.', 'In Drittländer übertragene PII muss in Einklang mit den anwendbaren Datentransfer-Vorschriften verarbeitet werden.', 1, 1220, 'active')
ON CONFLICT (catalog_id, code) DO NOTHING;

